var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"리벳이라고 했나?","JPN":"リベットだっけ？","ENG":"Rivet, right?","TWN":"你就是里維吧？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L4_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"네가 학회 측 하수인이라는 건, 할배들한테 지긋지긋할 정도로 들었어.","JPN":"お前が学会の殺し屋って話は、ジジイたちから飽きるほど聞いた。","ENG":"The old men told me again and again how you're one of the pawns in the Society.","TWN":"老頭們總是嘮叨你是學會的爪牙，我都聽煩了。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L5_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"학회 측에 붙기 전에는 뒷동네에서 꽤나 알아주는 용병이었다는 것도 함께 말이야.","JPN":"学会側につく前は、裏で有名な傭兵だったってこともな。","ENG":"Along with the fact that you were quite a famous mercenary in the back alleys before you started working with the Society.","TWN":"而且我還聽說你在投靠學會之前，是地下世界裡頗有名氣的傭兵。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"소녀의 비밀을 파헤치다니……! 응큼해!","JPN":"少女の秘密を暴くなんて……！　エッチ！","ENG":"You were digging around my past...?! How naughty!","TWN":"竟然揭穿少女的秘密……！想幹嘛！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"시끄럽고, 네가 왜 여기 있지?","JPN":"うるさい、なんでお前がここにいるんだ？","ENG":"Shut it. Why are you here?","TWN":"你好吵，你怎麼在這裡？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"숙청 사건 이후, 넌 학회장이 가장 신뢰하는 오른팔이라고 들었는데 말이야.","JPN":"粛清事件の後、お前は学会長がもっとも信頼してる右腕だって聞いたのにな。","ENG":"I heard you were the President's most trusted right hand.","TWN":"聽說肅清事件之後，你是學會會長最信任的心腹。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"잠깐……! 설마 학회도 교수의 행방을 쫓고 있는 거야?","JPN":"待てよ……！　まさか、学会も教授の行方を探してるのか？","ENG":"Wait...! Is the Society also after the Professor?","TWN":"等一下……！難道學會也在追查教授的下落？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"……풉!","JPN":"……プッ。","ENG":"...Pfft!","TWN":"……噗！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"푸하하하하하하하하!!","JPN":"あはははははははは！！","ENG":"Ha ha ha ha ha ha ha ha!!","TWN":"噗哈哈哈哈哈哈哈哈！！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_04"},{"id":"L13_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"내가…… 큭큭! 내가 레지나의 오른팔이라고?","JPN":"アタシ……ククッ！　アタシがレジーナの右腕？","ENG":"I'm... Ha ha! I'm Regina's right hand?","TWN":"我……呵呵！我是蕾佳娜的心腹？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐야, 아니야?","JPN":"なんだ、違うのか？","ENG":"Huh? You're not?","TWN":"什麼啊，不是嗎？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L17_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"올해 들은 헛소리 중에 제일 웃겼으니까! 기관에는 눈치 빠른 귀신들만 모인 줄 알았는데…….","JPN":"今年聞いた話で一番面白かったよ！　機関は勘のいいやつの集まりだって思ってたけど……","ENG":"It's the funniest thing I've heard this year! I thought the Institution only hired quick-witted folks.","TWN":"這是我今年聽到的笑話裡最搞笑的一個了！我以為機關的人都很聰明呢……"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L18_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"꼭 그렇지도 않나 봐, 애송이?","JPN":"そうでもないみたいだね、チビ。","ENG":"I guess that's not entirely the case, is it, kid?","TWN":"看來也不一定是那樣啊，小鬼？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L19_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐라고?","JPN":"なんだと？","ENG":"What?","TWN":"什麼？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_PRIDE"},"C":null,"R":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L21_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"잘 들어, 난 처음부터 레지나가 재밌어서 붙어있는 것뿐이거든.","JPN":"よく聞きな。アタシは最初からレジーナが面白いから学会側についてるだけ。","ENG":"Listen carefully. I'm only sticking around because Regina is fun.","TWN":"聽好了，我從一開始就覺得蕾佳娜有意思，所以才跟著她的。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"그런데 요즘 레지나는 뭘 하는지 저택에 꼼짝 않고 틀어박혀서 영 재미가 없단 말이지?","JPN":"でも、最近のレジーナ邸宅に引きこもってばっかりで、これっぽちも面白くない。","ENG":"But these days, she's no fun because she's just locked herself inside the mansion.","TWN":"可最近不知道蕾佳娜在做什麼，悶在家裡一動不動，一點意思都沒有。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"그래서 짜잔!","JPN":"それで、ジャジャーン！","ENG":"So… Tada!","TWN":"所以，鏘鏘！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L25_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"지루해진 리벳은 불쌍한 고고학부장님의 편이되기로 했습니다!","JPN":"暇になったリベットは、可哀想な考古学部長の味方になることにしました！","ENG":"I was bored and I decided to join forces with the poor, old, Dean of Archeology.","TWN":"無聊的里維決定站在可憐的考古學教授這一邊！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"무슨 헛소리야? 학회를 배신했다고!?","JPN":"どういうことだ？　学会を裏切ったのか！？","ENG":"What? You betrayed the Society?!","TWN":"你在胡說八道什麼？你背叛了學會？！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"헤헤헷! 왜냐하면 난 원래 강팀에서 싸우는 것보다 언더독이 취향에 맞걸랑!","JPN":"へへへっ！　だってアタシ、強豪よりもかませ犬が好みなんだもーん！","ENG":"Hehehe! I like underdogs better than fighting in the stronger teams!","TWN":"嘿嘿嘿！因為比起在強隊裡打架，我更喜歡弱隊！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"빠샤~!","JPN":"うりゃっ！","ENG":"Pew!","TWN":"我打～！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_TALK_04","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_PRIDE"},"R":null}},"sfx":"FX_COMBAT_ALL_MISSILE_RELOAD"},{"id":"L31_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"……크읏! 이게!","JPN":"……くうっ！　この！","ENG":"...Kgh! Why you!","TWN":"……咳！你！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"기억하지? 난 분명 너한테 데뷔 스테이지를 멋지게 장식할 권리를 줬다구?","JPN":"覚えてる？　アタシはアンタにデビューステージを華麗に彩る権利を与えたんだ。","ENG":"Do you remember? I gave you the right to fabulously decorate your debut performance.","TWN":"還記得吧？我明明有給你機會能帥氣出場。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"이젠 네가 나한테 스릴을 맛보게 해줄 차례야!","JPN":"次はアタシが、アンタにスリルを味わわせてあげる番だよ！","ENG":"Now it's your turn to thrill me!","TWN":"現在換你讓我興奮一下囉！"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"그래야 서로 공평하지 않겠어, 로이 버넷?","JPN":"アタシたち、これで公平になったでしょ？　ロイ・バーネット。","ENG":"Wouldn't that make it fair, Roy Burnett?","TWN":"這樣才互相公平吧，羅伊？"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"뭐, 좋아. 걸어오는 싸움을 마다할 필요는 없겠지.","JPN":"まあ、いい。売られたケンカを買わないワケにはいかないからな。","ENG":"Well, fine. I won't say no to a fight.","TWN":"很好，我也沒有必要拒絕找上門的戰鬥。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"ROI_PRYDWEN_NULL_NULL","text":{"KOREA":"처음 만났을 때랑은 다를 거야. 각오하는 게 좋을 걸?","JPN":"俺はもう、初めて会った時とは違う。覚悟しろよ。","ENG":"It's gonna be different from the first time we met. So buckle up.","TWN":"我和第一次見面的時候不一樣了，你最好做好心理準備。"},"stage":{"bg":"COUNTERSIDE_SNOW","bgm":"THEMA_ESPR","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"ROI_PRYDWEN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};